package pool

import (
    "database/sql"
    "fmt"
    "runtime"
)

type ManagedConn struct {
    db   *sql.DB
    name string
    dsn  string
}

func NewManagedConn(dsn, name string) (*ManagedConn, error) {
    db, err := sql.Open("postgres", dsn)
    if err != nil {
        return nil, fmt.Errorf("opening db: %w", err)
    }
    mc := &ManagedConn{db: db, name: name, dsn: dsn}
    runtime.SetFinalizer(mc, func(c *ManagedConn) {
        c.db.Close()
    })
    return mc, nil
}

type TempFile struct {
    path string
    fd   int
}

func NewTempFile(path string, fd int) *TempFile {
    tf := &TempFile{path: path, fd: fd}
    runtime.SetFinalizer(tf, func(f *TempFile) {
        syscallClose(f.fd)
        osRemove(f.path)
    })
    return tf
}

func syscallClose(fd int) {}
func osRemove(path string) {}
