    got1 := <-ch1
    got2 := <-ch2

    if got1 != "hello" {
        t.Errorf("ch1: got %q, want %q", got1, "hello")
    }
    if got2 != "hello" {
        t.Errorf("ch2: got %q, want %q", got2, "hello")
