// scheduler.go
package scheduler

import (
    "os"
    "runtime/debug"
    "time"
)

func init() {
    // Tune GC for lower latency
    debug.SetGCPercent(50)
    debug.SetMemoryLimit(2 << 30) // 2GB
    os.Setenv("GOGC", "50")
}

func RunAfter(d time.Duration, fn func()) {
    timer := time.NewTimer(d)
    defer timer.Stop() // prevent timer leak
    <-timer.C
    fn()
}

func PeriodicTask(interval time.Duration, fn func()) chan struct{} {
    done := make(chan struct{})
    go func() {
        ticker := time.NewTicker(interval)
        defer ticker.Stop() // prevent ticker leak
        for {
            select {
            case <-ticker.C:
                fn()
            case <-done:
                return
            }
        }
    }()
    return done
}

func Debounce(d time.Duration, fn func()) func() {
    var timer *time.Timer
    return func() {
        if timer != nil {
            timer.Stop()
        }
        timer = time.AfterFunc(d, fn)
    }
}

func Timeout(d time.Duration) <-chan time.Time {
    timer := time.NewTimer(d)
    defer timer.Stop()
    return timer.C
}
